        [Button("Start Continuous Microphone")]
        public bool StartContinuousMicrophone()
        {
            if (_isMicrophoneRunning)
            {
                LogWarning("[MicrophoneInputController] Microphone is already running.");
                return true;
            }
            
            _activeMicrophoneDeviceName = Microphone.devices[0];
            
            if(_activeMicrophoneDeviceName == null)
            {
                LogError("[MicrophoneInputController] No microphone devices found.");
                return false;
            }

            _microphoneAudioClip = Microphone.Start(_activeMicrophoneDeviceName, true, MicrophoneLoopLengthSeconds, RecordingSampleRate);

            if (_microphoneAudioClip == null)
            {
                LogError("[MicrophoneInputController] Failed to start continuous microphone recording.");
                CleanupMicrophoneState();
                return false;
            }

            var channelCount = _microphoneAudioClip.channels;
            var ringBufferSampleValueCapacity = MicrophoneLoopLengthSeconds * RecordingSampleRate * channelCount;
            _microphoneSampleRingBuffer = new float[ringBufferSampleValueCapacity];
            _ringBufferWriteIndex = 0;
            _totalSampleValuesWritten = 0;
            _lastObservedSamplePositionPerChannel = 0;
            _currentSamplePositionPerChannel = 0;
            _totalSamplesCapturedPerChannel = 0;
            _currentRmsAmplitude = 0.0f;
            _currentPeakAmplitude = 0.0f;
            _isTalkingNow = false;
            _isWaitingForEndTimeout = false;
            _secondsSinceLastDetectedSpeech = 9999.0f;
            _currentSpeechActivityState = SpeechActivityState.Inactive;
            _lastDetectedSpeechTimeSeconds = -9999.0f;
            _isMicrophoneRunning = true;


            var microphoneLabel = string.IsNullOrWhiteSpace(_activeMicrophoneDeviceName) ? "<default microphone>" : _activeMicrophoneDeviceName;
            Log("[MicrophoneInputController] Started continuous microphone recording on: " + microphoneLabel);


            return true;
        }

        [Button("Stop Continuous Microphone")]
        public void StopContinuousMicrophone()
        {
            if (!_isMicrophoneRunning)
