        private void Update()
        {
            if (!_isMicrophoneRunning)
            {
                _currentRmsAmplitude = 0.0f;
                _currentPeakAmplitude = 0.0f;
                _currentSamplePositionPerChannel = 0;
                _isTalkingNow = false;
                _isWaitingForEndTimeout = false;
                _secondsSinceLastDetectedSpeech = 9999.0f;
                _currentSpeechActivityState = SpeechActivityState.Inactive;
                return;
            }

            PumpNewMicrophoneSamplesIntoRingBuffer();
            UpdateSpeechDetectionState();
        }

        private void PumpNewMicrophoneSamplesIntoRingBuffer()
        {
            if (_microphoneAudioClip == null)
            {
                return;
            }

            var currentSamplePositionPerChannel = Microphone.GetPosition(_activeMicrophoneDeviceName);

            if (currentSamplePositionPerChannel < 0)
            {
                return;
            }

            _currentSamplePositionPerChannel = currentSamplePositionPerChannel;

            if (_lastObservedSamplePositionPerChannel < 0)
            {
                _lastObservedSamplePositionPerChannel = currentSamplePositionPerChannel;
                return;
            }

            if (currentSamplePositionPerChannel == _lastObservedSamplePositionPerChannel)
            {
                return;
            }

            var channelCount = _microphoneAudioClip.channels;
            var totalNewSamplesPerChannel = 0;

            if (currentSamplePositionPerChannel > _lastObservedSamplePositionPerChannel)
            {
                totalNewSamplesPerChannel = currentSamplePositionPerChannel - _lastObservedSamplePositionPerChannel;
                CopyMicrophoneClipRangeIntoRingBuffer(_lastObservedSamplePositionPerChannel, totalNewSamplesPerChannel, channelCount);
            }
            else
            {
                var samplesUntilLoopEndPerChannel = _microphoneAudioClip.samples - _lastObservedSamplePositionPerChannel;

                if (samplesUntilLoopEndPerChannel > 0)
                {
                    CopyMicrophoneClipRangeIntoRingBuffer(_lastObservedSamplePositionPerChannel, samplesUntilLoopEndPerChannel, channelCount);
                }

                if (currentSamplePositionPerChannel > 0)
                {
                    CopyMicrophoneClipRangeIntoRingBuffer(0, currentSamplePositionPerChannel, channelCount);
                }

                totalNewSamplesPerChannel = samplesUntilLoopEndPerChannel + currentSamplePositionPerChannel;
            }

            _lastObservedSamplePositionPerChannel = currentSamplePositionPerChannel;
            _totalSamplesCapturedPerChannel += totalNewSamplesPerChannel;
        }

        private void CopyMicrophoneClipRangeIntoRingBuffer(int startSamplePerChannel, int sampleCountPerChannel, int channelCount)
        {
            if (sampleCountPerChannel <= 0)
            {
                return;
            }

            var sampleValueCount = sampleCountPerChannel * channelCount;
            var sampleValues = new float[sampleValueCount];
            _microphoneAudioClip.GetData(sampleValues, startSamplePerChannel);

            for (var sampleIndex = 0; sampleIndex < sampleValues.Length; sampleIndex++)
            {
                _microphoneSampleRingBuffer[_ringBufferWriteIndex] = sampleValues[sampleIndex];
                _ringBufferWriteIndex = (_ringBufferWriteIndex + 1) % _microphoneSampleRingBuffer.Length;
                _totalSampleValuesWritten++;
            }
        }

        private void UpdateSpeechDetectionState()
        {
            var channelCount = ChannelCount;
            var amplitudeSampleValueCount = AmplitudeSampleWindowSizePerChannel * channelCount;

            if (!TryGetMostRecentSampleValues(amplitudeSampleValueCount, out var recentSampleValues))
            {
                _currentRmsAmplitude = 0.0f;
                _currentPeakAmplitude = 0.0f;
                _isTalkingNow = false;
                _isWaitingForEndTimeout = false;
                _secondsSinceLastDetectedSpeech = 9999.0f;
                _currentSpeechActivityState = SpeechActivityState.Inactive;
                return;
            }

            _currentRmsAmplitude = CalculateRmsAmplitude(recentSampleValues);
            _currentPeakAmplitude = CalculatePeakAmplitude(recentSampleValues);
            _isTalkingNow = _currentRmsAmplitude >= SpeechAmplitudeThreshold;

            if (_isTalkingNow)
            {
                _lastDetectedSpeechTimeSeconds = Time.unscaledTime;
            }

            _secondsSinceLastDetectedSpeech = Time.unscaledTime - _lastDetectedSpeechTimeSeconds;

            if (_isTalkingNow)
            {
                _isWaitingForEndTimeout = false;
                _currentSpeechActivityState = SpeechActivityState.TalkingNow;
                return;
            }

            if (_secondsSinceLastDetectedSpeech <= SpeechEndTimeoutSeconds)
            {
                _isWaitingForEndTimeout = true;
                _currentSpeechActivityState = SpeechActivityState.WaitingForEndTimeout;
                return;
            }

            _isWaitingForEndTimeout = false;
            _currentSpeechActivityState = SpeechActivityState.Inactive;
        }

        private float CalculateRmsAmplitude(float[] sampleValues)
        {
            if (sampleValues == null || sampleValues.Length == 0)
            {
                return 0.0f;
            }

            var sumOfSquares = 0.0f;

            for (var sampleIndex = 0; sampleIndex < sampleValues.Length; sampleIndex++)
            {
                var sampleValue = sampleValues[sampleIndex];
                sumOfSquares += sampleValue * sampleValue;
            }

            return Mathf.Sqrt(sumOfSquares / sampleValues.Length);
        }

        private float CalculatePeakAmplitude(float[] sampleValues)
        {
            if (sampleValues == null || sampleValues.Length == 0)
            {
                return 0.0f;
            }

            var peakAmplitude = 0.0f;

            for (var sampleIndex = 0; sampleIndex < sampleValues.Length; sampleIndex++)
            {
                var absoluteAmplitude = Mathf.Abs(sampleValues[sampleIndex]);

                if (absoluteAmplitude > peakAmplitude)
                {
                    peakAmplitude = absoluteAmplitude;
                }
            }

            return peakAmplitude;
        }

